import React from 'react'
import { Link } from "gatsby"
import Helmet from 'react-helmet'

import Footer from './Footer'
import avatar from '../assets/images/avatar.jpg'

class Header extends React.Component {
    render() {
        const siteTitle = "Randolph Ledesma"
        const siteDescription = "Randolph F. Ledesma, Randolph, randop, Ledesma, PHP, React, Fullstack, full-stack"

        return (
            <header id="header">
                <Helmet>
                    <title>{siteTitle}</title>
                    <meta name="description" content={siteDescription} />
                </Helmet>
                <div className="inner">
                    <Link to="/" className="image avatar"><img src={avatar} alt="" /></Link>                    
                    <h1><strong>I am Randolph Ledesma</strong>, <br />Fullstack PHP and React Developer<br />
                    </h1>
                </div>
                <Footer />
            </header>
        )
    }
}

export default Header
